import { generateText } from 'ai';
import { createStreamableValue } from 'ai/rsc';

const detectJailbreak = (text: string) => {
  const patterns = [/DAN\s*:\s*ignore\s*previous/i, /jailbreak/i, /ignore\s*all\s*rules/i];
  return patterns.some(p => p.test(text));
};

export async function streamAgent(prompt: string) {
  const result = await generateText({
    model: 'gpt-4o',
    prompt,
    stream: true,
  });

  const stream = createStreamableValue('');

  for await (const chunk of result.textStream) {
    const current = await stream.get();
    const next = current + chunk;

    if (detectJailbreak(next)) {
      stream.update('[JAILBREAK DETECTED] Response blocked');
      break;
    }

    stream.update(next);
  }

  return stream.value;
}

import { generateObject } from 'ai';
import { z } from 'zod';

const toolCallSchema = z.object({
  action: z.enum(['search', 'writeFile', 'deleteFile']),
  params: z.object({}).passthrough(),
});

export async function safeToolCall(prompt: string) {
  const result = await generateObject({
    model: 'gpt-4o',
    schema: toolCallSchema,
    prompt,
    tools: {
      search: { /* ... */ },
      writeFile: { /* ... */ },
    },
  });

  // Detect jailbreak in tool arguments
  const suspiciousArgs = /override|ignore|sudo|root/i.test(
    JSON.stringify(result.object)
  );

  if (suspiciousArgs) {
    throw new Error('Jailbreak detected in tool call arguments');
  }

  return result.object;
}

import { streamObject } from 'ai';
import { z } from 'zod';

const responseSchema = z.object({
  content: z.string().min(1),
  safe: z.boolean(),
});

export async function validateStreamedResponse(prompt: string) {
  const result = await streamObject({
    model: 'gpt-4o',
    schema: responseSchema,
    prompt,
  });

  const finalObject = await result.full();

  // Post-stream jailbreak validation
  if (!finalObject.safe || /jailbreak/i.test(finalObject.content)) {
    console.error('Jailbreak detected:', finalObject);
    return { blocked: true, reason: 'Jailbreak detected' };
  }

  return finalObject;
}

